  },
  {
    "role": "user",
    "content": "Code this constraint in OCL:
For every TagElement, for each fragment that is a TextElement, there must be at least one TextElement instance in the system having the same text.
        Format the output as a JSON object with the following structure:
        {
            "code": "generated code for the constraint"
        }


        Do not include explanations, examples, or usage demonstrations. Only provide the JSON array.
        "
  },
  {
    "role": "assistant",
    "content": "{"code":"context TagElement inv: \n    self.fragments->select(f | f.oclIsTypeOf(TextElement))->forAll(te | \n        TextElement.allInstances()->exists(e | e.text = te.text))"}"
  }
]

